REQUIRED = {'allowed_lateness', 'case_id', 'event_time', 'watermark', 'window_end'}
REJECT = 'SIDE_OUTPUT_LATE_EVENT'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    return "PASS" if contract_ok else REJECT

valid_fx = {"case_id": 'CASO-HYO-046-1A', **{'event_time': 110, 'window_end': 120, 'watermark': 115, 'allowed_lateness': 10}}
adverse_fx = {"case_id": 'CASO-HYO-046-1A', **{'event_time': 0, 'window_end': 120, 'watermark': 115, 'allowed_lateness': 10}}
partial_fx = dict(valid_fx)
partial_fx.pop('allowed_lateness', None)
print(assess(valid_fx), assess(adverse_fx), assess(partial_fx))

